import{_ as s,o as e,c as i,ak as n}from"./chunks/framework.BQh-lcRV.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tools/mac/index.md","filePath":"guide/tools/mac/index.md","lastUpdated":1775392610000}'),l={name:"guide/tools/mac/index.md"};function t(p,a,c,o,r,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to “常见问题”">​</a></h1><h3 id="环境变量与别名" tabindex="-1">环境变量与别名 <a class="header-anchor" href="#环境变量与别名" aria-label="Permalink to “环境变量与别名”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ vim ~/.bash_profile</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 别名</span></span>
<span class="line"><span>alias ll=&quot;ls -al&quot;</span></span>
<span class="line"><span>alias cdweb=&quot;cd /usr/local/var/www/htdocs&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 环境变量</span></span>
<span class="line"><span>PATH=$PATH:/usr/local/php/bin</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export PATH</span></span>
<span class="line"><span></span></span>
<span class="line"><span>$ source ~/.bash_profile</span></span></code></pre></div><h3 id="ulimit-n-xx-错误" tabindex="-1">ulimit -n xx 错误 <a class="header-anchor" href="#ulimit-n-xx-错误" aria-label="Permalink to “ulimit -n xx 错误”">​</a></h3><blockquote><p>错误描述</p></blockquote><p><code>bash: ulimit: open files: cannot modify limit: Invalid argument</code></p><blockquote><p>解决</p></blockquote><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ echo kern.maxfiles=65536 | sudo tee -a /etc/sysctl.conf</span></span>
<span class="line"><span>$ echo kern.maxfilesperproc=65536 | sudo tee -a /etc/sysctl.conf</span></span>
<span class="line"><span>$ sudo sysctl -w kern.maxfiles=65536</span></span>
<span class="line"><span>$ sudo sysctl -w kern.maxfilesperproc=65536</span></span>
<span class="line"><span>$ ulimit -n 65536 65536</span></span></code></pre></div><h3 id="无法修改文件" tabindex="-1">无法修改文件 <a class="header-anchor" href="#无法修改文件" aria-label="Permalink to “无法修改文件”">​</a></h3><ul><li><p>重启 Mac，按住 Command+R 键直到 Apple logo 出现，进入 Recovery Mode</p></li><li><p>点击 Utilities &gt; Terminal</p></li><li><p>在 Terminal 中输入 <code>csrutil disable</code>，之后回车</p></li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>csrutil disable</span></span></code></pre></div><ul><li>重启 Mac</li></ul><h3 id="mac-os-x文件系统的附加属性-如何彻底删除" tabindex="-1">Mac OS X文件系统的附加属性@如何彻底删除 <a class="header-anchor" href="#mac-os-x文件系统的附加属性-如何彻底删除" aria-label="Permalink to “Mac OS X文件系统的附加属性@如何彻底删除”">​</a></h3><p><a href="http://www.jianshu.com/p/3782d73cb3e8" target="_blank" rel="noreferrer">帮助</a></p><ul><li>查看</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>xattr -l hello.txt</span></span></code></pre></div><ul><li>删除</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>xattr -c *.txt</span></span></code></pre></div><h3 id="打开mac-osx原生的ntfs功能" tabindex="-1"><a href="http://www.tianwaihome.com/2014/07/mac-osx-ntfs.html" target="_blank" rel="noreferrer">打开Mac OSX原生的NTFS功能</a> <a class="header-anchor" href="#打开mac-osx原生的ntfs功能" aria-label="Permalink to “打开Mac OSX原生的NTFS功能”">​</a></h3><p>很多同学都会为如何在Mac下写入NTFS格式的磁盘而感到困惑，因为默认情况下，把一个NTFS格式的磁盘插入到Mac里，是只能读不能写的。用起来肯定很郁闷，很多同学也因此把移动硬盘分成了双分区，一个NTFS，一个HFS。其实在Mac下完全是可以写NTFS磁盘的</p><p>一种十分简单的方法是用第三方工具，Paragon NTFS for MAC。使用这种工具，虽然说是简单了，可是麻烦事也不少，一来是这个工具是要收费的，当然有破解版，不过破解版里有没有被植入什么，那就没有人知道了，二是这个工具本身就不怎么稳定，容易丢数据不说，每次OSX一更新，必须得等软件更新后才能用，总之，用起来不放心啊。</p><p>其实呢，大家并不需要困惑，OSX其实原生就支持NTFS，最早在OSX 10.5的时候，是可以直接写入NTFS的盘的，后来由于微软的限制，把这个功能给屏蔽了，我们可以通过命令行手动打开这个选项。</p>`,22)])])}const k=s(l,[["render",t]]);export{u as __pageData,k as default};
